mapper.update:
update base_entrust_relationship set
stock_org_id=#{bean.stockOrgId},
pay_receive_org_id=#{bean.receiveOrgId},
account_org_id=#{bean.receiveOrgId},
settment_org_id=#{bean.settleOrgId},
state = #{bean.state},
modified_by = #{bean.modifiedBy},
modified_date = #{bean.modifiedDate}
where  entrust_range = 2
and entrust_source = #{bean.entrustSource}
and entrust_source_id = #{bean.entrustSourceId}
and entrust_type = #{bean.entrustType}
and deleted_flag=0

